echo  "Enter a number to print the  factorial : "
read num
fact=1
for((i=1;i<n                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    um+1;i++))
do
   fact=$((i*fact))
done
echo "The factorial is : $fact"   
    
